 40→     * automatically shows system notifications when site creation is in progress and the app is in the background.
 41→     */
 42→    private var serviceEventConnection: ServiceEventConnection? = null
 43→    private var animatorSet: AnimatorSet? = null
 44→
 45→    private lateinit var binding: SiteCreationProgressScreenBinding
 46→    private val viewModel: SiteCreationProgressViewModel by activityViewModels()
 47→
 48→    override fun onAttach(context: Context) {
 49→        super.onAttach(context)
 50→        check(context is OnHelpClickedListener) { "Parent activity must implement OnHelpClickedListener." }
 51→    }
 52→
 53→    override fun onCreate(savedInstanceState: Bundle?) {
 54→        super.onCreate(savedInstanceState)
 55→        if (savedInstanceState == null) {
 56→            // we need to manually clear the service state to avoid sticky events from the previous SiteCreation flow.
 57→            SiteCreationService.clearSiteCreationServiceState()
 58→        }
 59→    }
 60→
 61→    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
 62→        super.onViewCreated(view, savedInstanceState)
 63→
 64→        binding = SiteCreationProgressScreenBinding.bind(view).apply {
 65→            observeState()
 66→            observeHelpClicks(requireActivity() as OnHelpClickedListener)
 67→            observeSiteCreationService()
 68→            fullscreenErrorWithRetry.setOnClickListeners()
 69→        }
 70→
 71→        (requireActivity() as AppCompatActivity).supportActionBar?.hide()
 72→
 73→        viewModel.start(requireNotNull(requireArguments().getParcelableCompat(ARG_STATE)))
 74→    }
 75→
 76→    private fun SiteCreationProgressScreenBinding.observeState() {
 77→        viewModel.uiState.observe(viewLifecycleOwner) { uiState ->
 78→            uiState?.run {
 79→                when (val ui = this@run) {
 80→                    is Loading -> siteCreationProgressCreatingSite.updateLoadingLayout(ui)
 81→                    is Error -> fullscreenErrorWithRetry.updateErrorLayout(ui)
 82→                }
 83→                siteCreationProgressCreatingSite.progressLayout.isVisible = progressLayoutVisibility
 84→                fullscreenErrorWithRetry.errorLayout.isVisible = errorLayoutVisibility
 85→            }
 86→        }
 87→    }
 88→
 89→    private fun observeSiteCreationService() {
 90→        viewModel.startCreateSiteService.observe(viewLifecycleOwner) { startServiceData ->
 91→            startServiceData?.let {
 92→                SiteCreationService.createSite(requireNotNull(activity), it.previousState, it.serviceData)
 93→            }
 94→        }
 95→        viewModel.onFreeSiteCreated.observe(viewLifecycleOwner) {
 96→            view?.announceForAccessibility(getString(R.string.new_site_creation_preview_title))
 97→        }
 98→    }
 99→
100→    private fun observeHelpClicks(listener: OnHelpClickedListener) {
101→        viewModel.onHelpClicked.observe(viewLifecycleOwner) {
102→            listener.onHelpClicked(HelpActivity.Origin.SITE_CREATION_CREATING)
103→        }
104→    }
