106→    private fun FullscreenErrorWithRetryBinding.setOnClickListeners() {
107→        errorRetry.setOnClickListener { viewModel.retry() }
108→        cancelWizardButton.setOnClickListener { viewModel.onCancelWizardClicked() }
109→        contactSupport.setOnClickListener { viewModel.onHelpClicked() }
110→    }
111→
112→    private fun FullscreenErrorWithRetryBinding.updateErrorLayout(errorUiState: Error) {
113→        errorUiState.run {
114→            uiHelpers.setTextOrHide(errorTitle, titleResId)
115→            uiHelpers.setTextOrHide(errorSubtitle, subtitleResId)
116→            uiHelpers.updateVisibility(contactSupport, errorUiState.showContactSupport)
117→            uiHelpers.updateVisibility(cancelWizardButton, errorUiState.showCancelWizardButton)
118→        }
119→    }
120→
121→    private fun SiteCreationProgressCreatingSiteBinding.updateLoadingLayout(
122→        progressUiState: Loading
123→    ) {
124→        progressUiState.apply {
125→            val newText = uiHelpers.getTextOfUiString(progressText.context, loadingTextResId)
126→            AppLog.d(AppLog.T.MAIN, "Changing text - animation: $animate")
127→            if (animate) {
128→                updateLoadingTextWithFadeAnimation(newText)
129→            } else {
130→                progressText.text = newText
131→            }
132→        }
133→    }
134→
135→    @SuppressLint("Recycle")
136→    private fun SiteCreationProgressCreatingSiteBinding.updateLoadingTextWithFadeAnimation(newText: CharSequence) {
137→        val animationDuration = AniUtils.Duration.SHORT
138→        val fadeOut = AniUtils.getFadeOutAnim(
139→            progressTextLayout,
140→            animationDuration,
141→            View.VISIBLE
142→        )
143→        val fadeIn = AniUtils.getFadeInAnim(
144→            progressTextLayout,
145→            animationDuration
146→        )
147→
148→        // update the text when the view isn't visible
149→        fadeIn.addListener(object : AnimatorListenerAdapter() {
150→            override fun onAnimationStart(animation: Animator) {
151→                progressText.text = newText
152→            }
153→
154→            override fun onAnimationEnd(animation: Animator) {
155→                super.onAnimationEnd(animation)
156→                animatorSet = null
157→            }
158→        })
159→        // Start the fade-in animation right after the view fades out
160→        fadeIn.startDelay = animationDuration.toMillis(progressTextLayout.context)
161→
162→        animatorSet = AnimatorSet().apply {
163→            playSequentially(fadeOut, fadeIn)
164→            start()
165→        }
166→    }
167→
168→    override fun onResume() {
169→        super.onResume()
170→        serviceEventConnection = ServiceEventConnection(context, SiteCreationService::class.java, viewModel)
171→    }
172→
173→    override fun onPause() {
174→        super.onPause()
175→        serviceEventConnection?.disconnect(context, viewModel)
176→    }
177→
178→    override fun onStop() {
179→        super.onStop()
180→        if (animatorSet?.isRunning == true) {
181→            animatorSet?.cancel()
182→        }
183→    }
